SELECT client_id AS clientId, client_name AS clientName, client_type1 AS clientType1, client_type2 AS clientType2, business_number AS businessNumber, ceo_name AS ceoName, client_tel AS clientTel, business_type AS businessType, business_product AS businessProduct, manager_name AS managerName, manager_dept AS managerDept, manager_tel AS managerTel, manager_email AS managerEmail, fax_number AS faxNumber, post_code AS postCode, address AS address, address_detail AS addressDetail, status_code AS statusCode, created_at AS createdAt FROM client
(client_name LIKE CONCAT('%', #{keyword}, '%') OR business_number LIKE CONCAT('%', #{keyword}, '%') OR ceo_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ${sortColumn} ${sortOrder} LIMIT #{pageStart}, #{perPageNum}
